namespace sv_baf2b82b758247fe8ba4b1d711b91258.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_baf2b82b758247fe8ba4b1d711b91258.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="d-flex flex-row">
    @* ── Left sidebar: filters (25%) ── *@
    <div class="pe-4" style="flex: 0 0 25%; max-width: 25%;">
        <div class="card">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">

                @* Category checkboxes *@
                <h6>Category</h6>
                @if (categories is not null)
                {
                    @foreach (var cat in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="cat-@cat"
                                   checked="@selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="cat-@cat">@cat</label>
                        </div>
                    }
                }
                else
                {
                    <p class="text-muted small">Loading…</p>
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small">Min Price</label>
                    <input type="number" class="form-control form-control-sm"
                           min="0" step="0.01" @bind="minPrice" />
                </div>
                <div class="mb-2">
                    <label class="form-label small">Max Price</label>
                    <input type="number" class="form-control form-control-sm"
                           min="0" step="0.01" @bind="maxPrice" />
                </div>

                <hr />

                @* In stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly"
                           @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
                <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
            </div>
        </div>
    </div>

    @* ── Main content area (75%) ── *@
    <div style="flex: 0 0 75%; max-width: 75%;">

        @if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label me-2 mb-0 small">Sort by:</label>
                    <select class="form-select form-select-sm d-inline-block w-auto" @bind="sortBy" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    Showing @(firstItem)–@(lastItem) of @(result.TotalCount) products
                </span>
            </div>

            @* Product grid *@
            <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4 mb-4">
                @foreach (var product in result.Items)
                {
                    <div class="col">
                        <div class="card h-100 product-card" @onclick="() => OnProductSelected(product)" style="cursor: pointer;">
                            <div class="bg-light d-flex align-items-center justify-content-center" style="height: 180px;">
                                <span class="text-muted">@product.Name</span>
                            </div>
                            <div class="card-body d-flex flex-column">
                                <h6 class="card-title">@product.Name</h6>
                                <p class="card-text fw-bold text-primary mb-1">@product.Price.ToString("C")</p>
                                <p class="card-text mb-2">@RenderStars(product.Rating)</p>
                                @if (!product.InStock)
                                {
                                    <span class="badge bg-danger mb-2">Out of Stock</span>
                                }
                                <button class="btn btn-sm btn-success mt-auto"
                                        disabled="@(!product.InStock)"
                                        @onclick="() => AddToCart(product)"
                                        @onclick:stopPropagation="true">
                                    Add to Cart
                                </button>
                            </div>
                        </div>
                    </div>
                }
            </div>

            @* Pagination *@
            <nav aria-label="Product pagination">
                <ul class="pagination justify-content-center">
                    <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(currentPage - 1)" disabled="@(currentPage == 1)">Previous</button>
                    </li>
                    @for (int i = 1; i <= totalPages; i++)
                    {
                        var pageNum = i;
                        <li class="page-item @(pageNum == currentPage ? "active" : "")">
                            <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                        </li>
                    }
                    <li class="page-item @(currentPage == totalPages ? "disabled" : "")">
                        <button class="page-link" @onclick="() => GoToPage(currentPage + 1)" disabled="@(currentPage == totalPages)">Next</button>
                    </li>
                </ul>
            </nav>
        }
    </div>
</div>

@code {
    [Parameter] public EventCallback<Product> OnProductClicked { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    private int totalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / PageSize);
    private int firstItem => result is null ? 0 : (result.Page - 1) * result.PageSize + 1;
    private int lastItem => result is null ? 0 : Math.Min(result.Page * result.PageSize, result.TotalCount);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAsync();
        await SearchAsync();
    }

    private async Task LoadCategoriesAsync()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
        }
        catch
        {
            categories = new List<string>();
        }
    }

    private async Task SearchAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            result = null;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await SearchAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await SearchAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > totalPages) return;
        currentPage = page;
        await SearchAsync();
    }

    private async Task OnProductSelected(Product product)
    {
        if (OnProductClicked.HasDelegate)
            await OnProductClicked.InvokeAsync(product);
    }

    private void AddToCart(Product product)
    {
        // Cart logic handled by parent / future service
    }

    private static string RenderStars(double rating)
    {
        int filled = (int)Math.Round(rating);
        return new string('★', filled) + new string('☆', 5 - filled);
    }
}

